import axios from 'axios';

const FILE_ID = 'NBHU5lsSfPTBMnlFVPxHNB';
const FIGMA_TOKEN = 'figd_9IgwTEDRk2P6kWhTjRvtOmkFcAKniW9pPya9ohwA';
const BUTTON_NODE_ID = '1-1334';

/**
 * Fetch data for a specific node in the Figma file
 */
export const fetchButtonData = async () => {
    try {
        const response = await axios.get(
            `https://api.figma.com/v1/files/${FILE_ID}/nodes?ids=${BUTTON_NODE_ID}`,
            {
                headers: { 'X-Figma-Token': FIGMA_TOKEN },
            }
        );
        const rawData = response.data.nodes[BUTTON_NODE_ID]?.document;
        if (!rawData) {
            throw new Error('No data found for the specified node ID');
        }
        return rawData;
    } catch (error) {
        console.error('Error fetching button data from Figma:', error);
        throw error;
    }
};

/**
 * Fetch full file data for debugging purposes
 */
export const fetchFullFileData = async () => {
    try {
        const response = await axios.get(`https://api.figma.com/v1/files/${FILE_ID}`, {
            headers: { 'X-Figma-Token': FIGMA_TOKEN },
        });
        console.log('Full File Data:', response.data.document); // Inspect the structure in console
    } catch (error) {
        console.error('Error fetching full file data:', error);
    }
};
